repl("Using AA form labels", "const aaPage2 = await openTab('https://www.aa.com/homePage.do');
await aaPage2.getByRole('button', {name:/Dismiss/i}).click().catch(e=>console.log('dismiss err '+e.message));
await aaPage2.getByLabel(/One way/i).click().catch(e=>console.log('oneway err '+e.message));
await aaPage2.getByLabel(/^From/i).fill('DCA');
await aaPage2.getByLabel(/^To/i).fill('MCO');
await aaPage2.getByLabel(/Number of passengers/i).selectOption('3');
await aaPage2.getByLabel(/Depart/i).fill('01/30/2027');
await aaPage2.getByRole('button', {name:/Search/i}).click();
await aaPage2.waitForLoadState('domcontentloaded', {timeout:30000}).catch(()=>{});
console.log('url='+aaPage2.url());
const aaSnapLabel1 = await snapshot(aaPage2);
console.log(aaSnapLabel1.tree);")

repl("Submitting AA baseline via fields", "await aaPage2.locator('#accept-recommended-btn-handler').click().catch(e=>console.log('accept '+e.message));
await aaPage2.locator('input[name="tripType"][value="oneWay"]').check({force:true});
await aaPage2.locator('input[name="originAirport"]').first().fill('DCA');
await aaPage2.locator('input[name="destinationAirport"]').first().fill('MCO');
await aaPage2.locator('select[name="adultOrSeniorPassengerCount"]').first().selectOption('3');
await aaPage2.locator('input[name="departDate"]').first().fill('01/30/2027');
await aaPage2.locator('input#flightSearchForm\\.button\\.reSubmit').first().click();
await aaPage2.waitForLoadState('domcontentloaded', {timeout:30000}).catch(()=>{});
console.log('url='+aaPage2.url());
const aaTitleAfter = await aaPage2.title();
console.log('title='+aaTitleAfter);
const aaSnapSubmit = await snapshot(aaPage2, {interactive:true});
console.log(aaSnapSubmit.tree);")

